import{_ as r,o as l,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"41. Travelling Allowance","description":"","frontmatter":{"title":"41. Travelling Allowance","eba":"Allied Health Professionals 2021-2026","topics":["allowances","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/allowances/41-travelling-allowance.md","filePath":"ebas/allied-health/allowances/41-travelling-allowance.md"}'),a={name:"ebas/allied-health/allowances/41-travelling-allowance.md"};function n(s,e,i,p,c,h){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_41-travelling-allowance" tabindex="-1">41. Travelling Allowance <a class="header-anchor" href="#_41-travelling-allowance" aria-label="Permalink to &quot;41. Travelling Allowance&quot;">​</a></h1><p><strong>41.1</strong> Rates The travelling allowance rates are as follows:</p><p>Engine capacity Cents per kilometre</p><p>Ordinary car Rotary engine car</p><p>1600cc (1.6 litre) 800cc (0.8 litre) 65 cents or less or less</p><p>1601cc - 2600cc 801cc - 1300cc 76 cents (1.601 litre - 2.6 litre) (0.801 litre - 1.3 litre)</p><p>2601cc (2.601 litre) and 1301cc (1.301 litre) and 77 cents over over</p><p><strong>41.2</strong> Travel - Recall</p><p><strong>(a)</strong> An Employee required to use their vehicle for transport from home to place of work and return outside of normal hours will receive the allowance at subclause</p><p><strong>41.1</strong> for each kilometre travelled.</p><p><strong>(b)</strong> At the Employee’s request, an Employee who is recalled to the Employer&#39;s premises for any purpose will be provided with transport (i.e. taxi or hire car) for the outward and return journeys and the Employer will be responsible for the cost.</p><p><strong>41.3</strong> Travel during normal working hours An Employee required to travel during normal working hours on Employer business will be:</p><p><strong>(a)</strong> provided with transport by the Employer and the Employer will be responsible for the cost; or</p><p><strong>(b)</strong> where the Employee agrees to use their own vehicle, receive the allowance at subclause 41.1 for each kilometre travelled on Employer business.</p><p><strong>41.4</strong> Reimbursement</p><p><strong>(a)</strong> Approved fares incurred by an Employee in the performance of their duty will be reimbursed by the Employer.</p><p><strong>(b)</strong> Any road tolls reasonably incurred by an Employee when using the Employee’s own vehicle under subclause 41.2 or 41.3, will be reimbursed by the Employer upon the production of appropriate evidence.</p><p><strong>41.5</strong> Parking An Employee undertaking travel under this clause 41 will be reimbursed for the cost of parking if that cost is incurred as a result of that travel.</p>',18)])])}const u=r(a,[["render",n]]);export{g as __pageData,u as default};
